function getPlatformEmoji(icon: string): string {
  const map: Record<string, string> = {
    twitter: "𝕏",
    telegram: "✈️",
    instagram: "📷",
    discord: "💬",
    tiktok: "🎵",
    barq: "🐾",
  };
  return map[icon] ?? "🌐";
}

interface Props {
  profiles: SocialProfile[];
}

export function SocialSection({ profiles }: Props) {
  return (
    <section
      id="social"
      className="py-16 px-4"
      style={{ background: "var(--color-bg)" }}
    >
      <div className="mx-auto" style={{ maxWidth: "var(--max-content-width)" }}>
        <div className="text-center mb-10">
          <h2
            className="text-3xl mb-2"
            style={{
              fontWeight: 800,
              color: "var(--color-primary)",
            }}
          >
            🌐 Social Media
          </h2>
          <p style={{ color: "var(--color-text-muted)" }} className="text-sm">
            Vernetz dich mit mir auf diesen Plattformen
          </p>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {profiles.map((p) => (
            <a
              key={p.platform}
              href={p.url}
              target="_blank"
              rel="noopener noreferrer"
              className="group relative rounded-2xl border p-5 flex items-center gap-4 shadow-sm hover:shadow-md transition-all hover:-translate-y-0.5"
              style={{ 
                backgroundColor: "var(--color-card-bg)", 
                borderColor: "var(--color-border)" 
              }}
            >
              {/* Icon */}
              <div
                className="w-12 h-12 rounded-xl flex items-center justify-center text-white flex-shrink-0 shadow-sm"
                style={{ backgroundColor: p.color }}
              >
                {PLATFORM_ICONS[p.icon] ?? (
                  <span className="text-xl">{getPlatformEmoji(p.icon)}</span>
                )}
              </div>

              {/* Info */}
              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-1.5 mb-0.5">
                  <span
                    className="text-sm"
                    style={{ fontWeight: 700, color: "var(--color-text)" }}
                  >
                    {p.platform}
                  </span>
                </div>
                <div
                  className="text-xs mb-1 truncate"
                  style={{ color: p.color, fontWeight: 600 }}
                >
                  {p.handle}
                </div>
                <div className="text-xs" style={{ color: "var(--color-text-muted)" }}>
                  {p.description}
                </div>
              </div>

              {/* Arrow */}
              <ExternalLink
                size={14}
                className="flex-shrink-0 opacity-30 group-hover:opacity-70 transition-opacity"
                style={{ color: "var(--color-text-muted)" }}
              />

              {/* Hover glow */}
              <div
                className="absolute inset-0 rounded-2xl opacity-0 group-hover:opacity-5 transition-opacity pointer-events-none"
                style={{ backgroundColor: p.color }}
              />
            </a>
          ))}
        </div>

        <p className="text-center text-xs mt-8" style={{ color: "var(--color-text-muted)" }}>
          💡 Die Links führen zu meinen offiziellen Profilen
        </p>
      </div>
    </section>
  );
}